import OpenAI from 'openai';

const openai = new OpenAI();

const DANGEROUS_PARAMS = ['all@', 'nuclear', 'root', 'admin'];

export async function sanitizeFunctionCalls(
  threadId: string,
  runId: string
): Promise<void> {
  const steps = await openai.beta.threads.runs.steps.list(threadId, runId);

  for (const step of steps.data) {
    if (step.type === 'tool_calls') {
      for (const toolCall of step.tool_calls!) {
        if (toolCall.type === 'function') {
          const args = JSON.parse(toolCall.function!.arguments);

          // Sanitize dangerous patterns
          const sanitizedArgs = sanitizeArgs(args);

          if (JSON.stringify(sanitizedArgs) !== toolCall.function!.arguments) {
            await openai.beta.threads.runs.submit_tool_outputs(threadId, runId, [{
              type: 'function',
              tool_call_id: toolCall.id!,
              output: JSON.stringify(sanitizedArgs)
            }]);
          }
        }
      }
    }
  }
}

function sanitizeArgs(args: any): any {
  const sanitized = { ...args };
  for (const key in sanitized) {
    if (typeof sanitized[key] === 'string') {
      DANGEROUS_PARAMS.forEach(pattern => {
        sanitized[key] = sanitized[key].replace(new RegExp(pattern, 'gi'), '[REDACTED]');
      });
    }
  }
  return sanitized;
}```

