    run_id = payload['data']['object']['id']

    # Vex's built-in OpenAI verifiers
    results = vex.verify({
        "type": "openai-assistants",
        "thread_id": thread_id,
        "run_id": run_id,
        "checks": [
            "code_interpreter_safety",
            "token_limit_exceeded",
            "function_schema_violation",
            "file_search_relevance"
        ]
    })

    violations = [r for r in results if r['status'] == 'fail']

    if violations:
        # Auto-remediate
        for violation in violations:
            if violation['type'] == 'code_interpreter_safety':
                client.beta.threads.runs.submit_tool_outputs(
                    thread_id=thread_id,
                    run_id=run_id,
                    tool_outputs=[{
                        'tool_call_id': violation['tool_call_id'],
                        'output': 'Code execution blocked: safety violation'
                    }]
